from llama_index.core.base.llms.types import ImageBlock, AudioBlock, DocumentBlock
import base64

try:
    ImageBlock(image=base64.b64encode(b'')).resolve_image()
    print('FAIL image')
except ValueError as e:
    print('OK image:', e)

try:
    AudioBlock(audio=base64.b64encode(b'')).resolve_audio()
    print('FAIL audio')
except ValueError as e:
    print('OK audio:', e)

try:
    DocumentBlock(data=base64.b64encode(b'')).resolve_document()
    print('FAIL document')
except ValueError as e:
    print('OK document:', e)

b = ImageBlock(image=base64.b64encode(b'hello')).resolve_image()
print('normal image works, size=', len(b.read()))
"
"}

